using System.ComponentModel;
using System.Text;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using OpenAI;

var builder = Host.CreateApplicationBuilder(args);

builder.Services.AddSingleton<ResearchTools>();

builder.Services.AddChatClient(pipeline => pipeline
    .UseLogging()
    .Use(innerClient => new FunctionInvokingChatClient(innerClient) { MaximumRoundtrips = 10 })
    .UseOpenAIChatClient(
        builder.Configuration["AI:Model"] ?? "gpt-4o-mini-2024-07-18",
        new OpenAIClient(
            builder.Configuration["AI:ApiKey"]
                ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
                ?? throw new InvalidOperationException(
                    "Set the AI:ApiKey configuration value or OPENAI_API_KEY environment variable."))));

builder.Logging.SetMinimumLevel(LogLevel.Warning);

using var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var tools = host.Services.GetRequiredService<ResearchTools>();
var loggerFactory = host.Services.GetRequiredService<ILoggerFactory>();

var agent = new ChatClientAgent(
    chatClient,
    name: "ResearchAgent",
    description: "An AI research assistant that searches the web and takes notes to produce a summary.",
    instructions: """
        You are a research assistant. When given a topic, follow this process:
        1. Use the SearchWeb tool multiple times with different queries to gather information.
        2. Use the SaveNote tool to record important findings as you go.
        3. Use the GetNotes tool to review what you've collected.
        4. Provide a comprehensive summary of your research findings.

        Be thorough — search from multiple angles and save key facts before summarizing.
        """,
    tools:
    [
        AIFunctionFactory.Create(tools.SearchWeb),
        AIFunctionFactory.Create(tools.SaveNote),
        AIFunctionFactory.Create(tools.GetNotes),
    ],
    loggerFactory: loggerFactory);

Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent              ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();
Console.WriteLine("Enter a topic to research (or 'quit' to exit):");

while (true)
{
    Console.Write("\n> ");
    var topic = Console.ReadLine();
    if (string.IsNullOrWhiteSpace(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
    {
        break;
    }

    tools.ClearNotes();

    Console.WriteLine($"\nResearching: {topic}\n");

    var session = new ChatClientAgentSession();
    var runOptions = new ChatClientAgentRunOptions(new ChatOptions { Temperature = 0f });

    try
    {
        await foreach (var update in agent.RunStreamingAsync(
            $"Research the following topic and provide a comprehensive summary: {topic}",
            session,
            runOptions))
        {
            Console.Write(update.Text);
        }

        Console.WriteLine();
    }
    catch (Exception ex)
    {
        Console.WriteLine($"\nError: {ex.Message}");
    }
}

Console.WriteLine("\nGoodbye!");

/// <summary>
/// Provides web search and note-taking tools for the research agent.
/// </summary>
sealed class ResearchTools
{
    private readonly List<string> _notes = [];
    private readonly HttpClient _httpClient = new();

    [Description("Searches the web for information on a given query. Returns search result snippets.")]
    public async Task<string> SearchWeb(
        [Description("The search query to look up on the web.")] string query,
        CancellationToken cancellationToken = default)
    {
        Console.WriteLine($"  🔍 Searching: {query}");

        try
        {
            // Use Wikipedia API as a real, free search source
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://en.wikipedia.org/w/api.php?action=query&list=search&srsearch={encoded}&srlimit=3&format=json&utf8=1";

            _httpClient.DefaultRequestHeaders.UserAgent.Clear();
            _httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

            var response = await _httpClient.GetStringAsync(url, cancellationToken);

            return response;
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Please try a different query.";
        }
    }

    [Description("Saves a research note. Use this to record important facts and findings during research.")]
    public string SaveNote(
        [Description("The note content to save.")] string content,
        [Description("A short label or category for the note.")] string label)
    {
        _notes.Add($"[{label}] {content}");
        Console.WriteLine($"  📝 Note saved: [{label}]");
        return $"Note saved under '{label}'. Total notes: {_notes.Count}.";
    }

    [Description("Retrieves all saved research notes collected so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes saved yet.";
        }

        var sb = new StringBuilder();
        sb.AppendLine($"Research notes ({_notes.Count} total):");
        for (var i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"  {i + 1}. {_notes[i]}");
        }

        return sb.ToString();
    }

    public void ClearNotes() => _notes.Clear();
}

